import React, { useEffect, useState } from 'react';
import axios from 'axios';
import {
  Container,
  TextField,
  MenuItem,
  Button,
  Typography,
  Box,
  Paper
} from '@mui/material';

function App() {
  const [clinics, setClinics] = useState([]);

  const [form, setForm] = useState({
    clinic_id: '',
    city: '',
    state: '',
    region: '',
    patient_name: '',
    patient_phone: '',
    channel: '',
    service_type: '',
    description: ''
  });

  // 🔥 CARREGAR CLÍNICAS
  useEffect(() => {
    axios.get('http://localhost:3001/clinics')
      .then(res => {
        console.log("CLINICS:", res.data);
        setClinics(res.data);
      })
      .catch(err => console.error(err));
  }, []);

  // 🔥 SELEÇÃO DE CLÍNICA
  const handleClinicChange = (id) => {
    const clinic = clinics.find(c => c.id === parseInt(id));

    if (clinic) {
      setForm({
        ...form,
        clinic_id: clinic.id,
        city: clinic.city || '',
        state: clinic.state || '',
        region: clinic.region || ''
      });
    }
  };

  // 🔥 ENVIO
  const handleSubmit = async () => {
    if (!form.clinic_id || !form.patient_name || !form.description) {
      alert('Preencha os campos obrigatórios');
      return;
    }

    try {
      await axios.post('http://localhost:3001/complaints', form);

      alert('Reclamação salva com sucesso!');

      setForm({
        clinic_id: '',
        city: '',
        state: '',
        region: '',
        patient_name: '',
        patient_phone: '',
        channel: '',
        service_type: '',
        description: ''
      });

    } catch (error) {
      console.error(error);
      alert('Erro ao salvar');
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={4} sx={{ p: 4, mt: 5, borderRadius: 3 }}>

        <Typography variant="h5" fontWeight="bold" gutterBottom>
          Cadastro de Reclamação
        </Typography>

        {/* CLÍNICA */}
        <TextField
          select
          label="Clínica"
          fullWidth
          margin="normal"
          value={form.clinic_id}
          onChange={(e) => handleClinicChange(e.target.value)}
        >
          {clinics.map(c => (
            <MenuItem key={c.id} value={c.id}>
              {c.name}
            </MenuItem>
          ))}
        </TextField>

        {/* AUTO */}
        <TextField label="Cidade" value={form.city} fullWidth margin="normal" disabled />
        <TextField label="Estado" value={form.state} fullWidth margin="normal" disabled />
        <TextField label="Região" value={form.region} fullWidth margin="normal" disabled />

        {/* PACIENTE */}
        <TextField
          label="Nome do paciente"
          fullWidth
          margin="normal"
          value={form.patient_name}
          onChange={(e) => setForm({ ...form, patient_name: e.target.value })}
        />

        <TextField
          label="Telefone"
          fullWidth
          margin="normal"
          value={form.patient_phone}
          onChange={(e) => setForm({ ...form, patient_phone: e.target.value })}
        />

        {/* CANAL */}
        <TextField
          select
          label="Canal"
          fullWidth
          margin="normal"
          value={form.channel}
          onChange={(e) => setForm({ ...form, channel: e.target.value })}
        >
          <MenuItem value="whatsapp">WhatsApp</MenuItem>
          <MenuItem value="email">Email</MenuItem>
          <MenuItem value="phone">Telefone</MenuItem>
          <MenuItem value="google">Google</MenuItem>
          <MenuItem value="facebook">Facebook</MenuItem>
          <MenuItem value="instagram">Instagram</MenuItem>
          <MenuItem value="reclame_aqui">Reclame Aqui</MenuItem>
          <MenuItem value="nps">NPS</MenuItem>
        </TextField>

        {/* SERVIÇO */}
        <TextField
          select
          label="Tipo de serviço"
          fullWidth
          margin="normal"
          value={form.service_type}
          onChange={(e) => setForm({ ...form, service_type: e.target.value })}
        >
          <MenuItem value="clinico">Clínico Geral</MenuItem>
          <MenuItem value="ortodontia">Ortodontia</MenuItem>
          <MenuItem value="implante">Implante</MenuItem>
          <MenuItem value="endodontia">Endodontia</MenuItem>
        </TextField>

        {/* DESCRIÇÃO */}
        <TextField
          label="Descrição"
          multiline
          rows={4}
          fullWidth
          margin="normal"
          value={form.description}
          onChange={(e) => setForm({ ...form, description: e.target.value })}
        />

        {/* BOTÃO */}
        <Box mt={3}>
          <Button variant="contained" fullWidth size="large" onClick={handleSubmit}>
            Salvar
          </Button>
        </Box>

      </Paper>
    </Container>
  );
}

export default App;
